    public void Validate_Null_ReturnsFalse()
    {
        var validator = new InputValidator();
        var result = validator.Validate(null);
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual("Input cannot be empty", result.ErrorMessage);
    }

