Use MSTest's `[DataTestMethod]` with `[DataRow]` to parameterize your tests. You can collapse all those methods into two — one for invalid inputs, one for valid:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    private InputValidator _validator = null!;

    [TestInitialize]
    public void Setup() => _validator = new InputValidator();

    [DataTestMethod]
    [DataRow(null, "Input cannot be empty", DisplayName = "Null")]
    [DataRow("", "Input cannot be empty", DisplayName = "Empty string")]
    [DataRow("   ", "Input cannot be empty", DisplayName = "Whitespace only")]
    [DataRow("ab", "Input must be at least 3 characters", DisplayName = "Too short")]
    [DataRow("hello<script>", "Input contains invalid characters", DisplayName = "Special chars")]
    public void Validate_InvalidInput_ReturnsFalse(string? input, string expectedError)
    {
        var result = _validator.Validate(input);
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    // DataRow can't inline `new string(...)`, so use DynamicData for generated inputs.
    [DataTestMethod]
    [DynamicData(nameof(TooLongInputs), DynamicDataSourceType.Method)]
    public void Validate_TooLong_ReturnsFalse(string input, string expectedError)
    {
        var result = _validator.Validate(input);
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    private static IEnumerable<object[]> TooLongInputs()
    {
        yield return [new string('x', 256), "Input must not exceed 255 characters"];
    }

    [DataTestMethod]
    [DataRow("hello-world", DisplayName = "Typical valid input")]
    [DataRow("abc", DisplayName = "Min length (3)")]
    public void Validate_ValidInput_ReturnsTrue(string input)
    {
        var result = _validator.Validate(input);
        Assert.IsTrue(result.IsValid);
        Assert.IsNull(result.ErrorMessage);
    }

    [DataTestMethod]
    [DynamicData(nameof(ValidBoundaryInputs), DynamicDataSourceType.Method)]
    public void Validate_ValidBoundary_ReturnsTrue(string input)
    {
        var result = _validator.Validate(input);
        Assert.IsTrue(result.IsValid);
        Assert.IsNull(result.ErrorMessage);
    }

    private static IEnumerable<object[]> ValidBoundaryInputs()
    {
        yield return [new string('a', 255)]; // max length
    }
}
```

**Key points:**

- **`[DataRow]`** — for simple compile-time constants. Adding a case = adding one line.
- **`[DynamicData]`** — for cases needing runtime construction (like `new string(...)`).
- **`[TestInitialize]`** — eliminates repeated `new InputValidator()`.
- **`DisplayName`** — gives each case a readable name in test output.
